	time.Sleep(10 * time.Millisecond)

	// Create policies for different namespaces
	policy1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-1",
			Namespace: "ns-1",
		},
		Spec: &api.Rule{EndpointSelector: api.NewESFromLabels()},
	}

	policy2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-1",
			Namespace: "ns-2",
		},
		Spec: &api.Rule{EndpointSelector: api.NewESFromLabels()},
	}

	// Add both policies
	event1 := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Key:    resource.Key{Name: "policy-1", Namespace: "ns-1"},
		Object: policy1,
	}
	event1.Done_ = make(chan error, 1)
	fakeRes.events <- event1

	event2 := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Key:    resource.Key{Name: "policy-1", Namespace: "ns-2"},
		Object: policy2,
	}
	event2.Done_ = make(chan error, 1)
	fakeRes.events <- event2

	time.Sleep(10 * time.Millisecond)

	// Both namespaces should have count 1
	controller.mu.RLock()
	assert.Equal(t, 1, controller.namespacePolicyCounts["ns-1"])
	assert.Equal(t, 1, controller.namespacePolicyCounts["ns-2"])
	controller.mu.RUnlock()

	// Both should be within quota
	err1 := controller.CheckQuota("ns-1")
	err2 := controller.CheckQuota("ns-2")
	assert.NoError(t, err1)
	assert.NoError(t, err2)
}

func TestPolicyQuotaController_MaxQuotaEdgeCases(t *testing.T) {
	// Test with max quota of 1
	maxPolicies := 1
	fakeRes := newFakeResource()
	controller := NewPolicyQuotaController(maxPolicies, fakeRes)

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
		Spec: &api.Rule{EndpointSelector: api.NewESFromLabels()},
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go controller.Run(ctx)
	time.Sleep(10 * time.Millisecond)

	// Initially should be OK
	err := controller.CheckQuota("test-ns")
	assert.NoError(t, err)

	// Add one policy
	event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Key:    resource.Key{Name: "test-policy", Namespace: "test-ns"},
		Object: policy,
	}
	event.Done_ = make(chan error, 1)
	fakeRes.events <- event

	time.Sleep(10 * time.Millisecond)

	// Now should exceed quota
	err = controller.CheckQuota("test-ns")
	assert.Error(t, err)
}

